#!/usr/bin/env bash
# 720.sh — 全景 720 漫游制作 SOP walkthrough for Web 线上展览开发 (虚拟展厅).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="Web 线上展览开发 (虚拟展厅)"
WORKFLOW="全景 720 漫游制作"

usage() {
  cat <<EOF
720.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./720.sh             # interactive
  ./720.sh --dry-run
  ./720.sh --json
  ./720.sh --explain
  ./720.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "全景 720 漫游制作" 工作流。

一句话: 从「要实景漫游但不需要真 3D 交互」到「多张全景串联成带热点的虚拟游」——最低成本主力路线。

入门 SOP 共 5 步, 失败模式自检 3 项。

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**拍摄规划 + 全景采集**：定点位（节点密度决定漫游连贯度）；全景相机/鱼眼拼接拍 equirect；保证曝光一致 (evidence: [T02-S016, S019])"
  "**拼接 / 后处理**：HDR、去三脚架、补光、统一白平衡 (evidence: [T03-S013 类比])"
  "**搭 viewer + 串联**：开源选 Pannellum（最轻 21KB）/ Photo Sphere Viewer（要视频/VR/楼层图/陀螺仪选它）；商业选 krpano；节点间建跳转 (evidence: [T02-S016, S017, S019])"
  "**加热点 / 导览 / 楼层图**：图文/音频热点、平面图定位、语音讲解 (evidence: [T02-S016])"
  "**发布 / 嵌入**：自托管或平台；移动端手势/陀螺仪验收 (evidence: [T02-S016, S017])"
)
declare -a FAILURE_MODES=(
  "点位太疏 → 漫游跳跃：按空间复杂度加密节点，转角/门口必设点 (evidence: [T02-S016])"
  "曝光不一致 → 接缝/明暗跳：现场统一白平衡 + 后期 HDR (evidence: [T03-S013])"
  "把全景当真 3D 卖 → 验收翻车：合同明确\"全景=看图跳点，不能走动/绕物/交互\" (evidence: [T02-S016])"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "720-walkthrough"
fi
